438→
439→                if (currentReaction === data.reactionType) {
440→                    // Toggle off
441→                    nextReaction = null;
442→                    nextCount = Math.max(currentCount - 1, 0);
443→                } else if (currentReaction) {
444→                    // Switch reaction (count stays same)
445→                    nextReaction = data.reactionType;
446→                    nextCount = currentCount;
447→                } else {
448→                    // New reaction
449→                    nextReaction = data.reactionType;
450→                    nextCount = currentCount + 1;
451→                }
452→
453→                return {
454→                    ...journal,
455→                    user_reaction: nextReaction,
456→                    reaction_count: [{ count: nextCount }],
457→                };
458→            };
459→
460→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
461→            queryClient.setQueriesData({ queryKey: ['journals-following'] }, (old) => updateInfiniteJournalsCache(old, updater));
462→            queryClient.setQueriesData({ queryKey: ['journals-for-you'] }, (old) => updateInfiniteJournalsCache(old, updater));
463→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
464→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
465→
466→            return { previousData };
467→        },
468→
469→        onError: (err, data, context) => {
470→            context?.previousData?.forEach(([key, value]) => {
471→                queryClient.setQueryData(key, value);
472→            });
473→        },
474→
475→    });
476→
477→    const guardedMutate = (variables, options) => {
478→        const journalKey = toJournalKey(variables?.journalId);
479→        if (journalKey && inFlightRef.current.has(journalKey)) return;
480→
481→        if (journalKey) inFlightRef.current.add(journalKey);
482→
483→        mutation.mutate(variables, {
484→            ...options,
485→            onSettled: (data, error, vars, context) => {
486→                if (journalKey) inFlightRef.current.delete(journalKey);
487→                options?.onSettled?.(data, error, vars, context);
488→            },
489→        });
490→    };
491→
492→    return { ...mutation, mutate: guardedMutate };
493→}
